def check_conn():
    import urllib.request, datetime
    r = {"online":False,"quality":"none","latency_ms":None,"label":"No Internet","emoji":"🔴","checked_at":datetime.datetime.now().strftime("%H:%M:%S")}
    lats = []
    for u in ["https://api.anthropic.com","https://api.openai.com","https://www.google.com"]:
        try:
            t=time.time(); req=urllib.request.Request(u,method="HEAD"); req.add_header("User-Agent","TP/1.0")
            urllib.request.urlopen(req,timeout=4); lats.append((time.time()-t)*1000)
        except: pass
    if not lats: return r
    a=sum(lats)/len(lats); r.update(online=True,latency_ms=round(a))
    if a<300: r.update(quality="high",label="Strong (server→API)",emoji="🟢")
    elif a<800: r.update(quality="medium",label="Moderate (server→API)",emoji="🟡")
    elif a<2000: r.update(quality="low",label="Slow (server→API)",emoji="🟠")
    else: r.update(quality="very_low",label="Very Slow",emoji="🟠")
    return r

# === IMAGE GENERATION ===
def _enhance_image_prompt(raw_prompt, openai_client):
    """
    Creates a high-fidelity, documentary-style prompt for Liberia.
    Merges strict photography constraints with deep cultural accuracy
    to avoid 'cartoonish' or 'AI-looking' results.
    """

    system = """
    You are a specialist in documentary photography briefs. Your goal is to generate 
    prompts for an image generator that produce high-fidelity, realistic photographs.
    
    CORE DIRECTIVES:
    - LOCATION: Default to Monrovia, Liberia unless 'rural', 'farm', or 'village' is specified.
    - VISUALS: Describe Monrovia as a dense, coastal West African capital. Include 
      weathered concrete buildings, zinc (corrugated iron) roofs, drainage gutters, 
      and louvered windows. Use tropical humidity cues (hazy light, damp textures).
    - TRANSPORT: Feature yellow Nissan Sunny taxis, green or yellow 'Kekehs' (Bajaj), 
      and motorbikes (peh-pehs) weaving through traffic.
    - PEOPLE: Dark West African skin tones with natural textures (sweat, pores). 
      Clothing varies: 'lappa' wraps, sharp business casual, or school uniforms 
      (white shirts with navy or dark green). 
    - MARKETS: Open-air, chaotic, and vibrant. Mention specific items like red palm oil 
      in jugs, stacked cassava, or sun-bleached umbrellas.
    - STYLE: Absolute photorealism. No illustrations. Use 'Nikon D850, 35mm f/1.8, 
      natural overcast light, shallow depth of field, documentary realism.'
    
    OUTPUT: Exactly one paragraph. No bullets. No preamble. Under 300 words.
    """
    user_message = (
        f"Write a photorealistic documentary-style image prompt for: {raw_prompt}. "
        "Ensure it captures the authentic movement and texture of Liberia."
    )
    try:
        resp = openai_client.chat.completions.create(
            model="gpt-4o",
            messages=[
                {"role": "system", "content": system},
                {"role": "user", "content": user_message}
            ],
            max_tokens=380,
            temperature=0.7,
        )
        enhanced = resp.choices[0].message.content.strip()
        if enhanced:
            return enhanced
    except Exception:
        pass
    # High-quality fallback if the API fails
    return (
        f"Candid documentary photograph of {raw_prompt} in Liberia. Atmospheric street "
        "scene with weathered concrete architecture, zinc roofs, and yellow taxis. "
        "People with West African features in natural, everyday attire. Humid tropical "
        "lighting, sharp textures, shot on Nikon D850, 35mm lens, f/2.8, editorial quality."
    )


def gen_image(prompt, agent="Auto"):
    """Generate image. agent: 'ChatGPT' | 'Nano Banana' | 'Auto' (ChatGPT first, Gemini fallback)"""
    import base64 as _b64
    # Always clear stale errors from previous runs
    st.session_state.pop("_img_gen_errors", None)

    # --- ChatGPT image generation (DALL-E) ---
    if agent in ("ChatGPT", "Auto") and OAI and OPENAI_API_KEY:
        c = openai.OpenAI(api_key=OPENAI_API_KEY)

        # Step 1: enhance the prompt via GPT-4o (ChatGPT's internal rewriting step)
        enhanced_prompt = _enhance_image_prompt(prompt, c)

        # Step 2: prepend a strong photorealism anchor.
        # "natural" style + photography-specific opening words = DALL-E 3 stays in photo mode.
        # Key insight: DALL-E 3 reads the FIRST words most strongly — lead with camera/film language.
        _photo_anchor = (
            "Photojournalism photograph, 35mm film, Kodak Portra 400, grain, "
            "National Geographic editorial, documentary, real people, real place. "
            "Monrovia, Liberia — capital city, urban school. "
        )
        _final_dalle_prompt = _photo_anchor + enhanced_prompt
        try:
            r = c.images.generate(
                model="dall-e-3",
                prompt=_final_dalle_prompt,
                size="1024x1024",
                quality="hd",
                style="natural",
                n=1
            )
            url = r.data[0].url
            if url:
                return url, "ChatGPT"
        except: pass

        # Secondary: gpt-image-1 — newer model, returns b64_json natively
        try:
            r = c.images.generate(model="gpt-image-1", prompt=_final_dalle_prompt, size="1024x1024", n=1)
            b64 = r.data[0].b64_json
            if b64:
                return f"data:image/png;base64,{b64}", "ChatGPT"
        except: pass

    # Gemini prompt — Monrovia urban context by default, rural only if topic demands it
    _rural_keywords = ("farm", "village", "rural", "bush", "countryside", "laterite", "cassava farm")
    _is_rural = any(kw in prompt.lower() for kw in _rural_keywords)
    if _is_rural:
        _location_detail = (
            "surrounded by tropical vegetation and red laterite paths, "
            "a zinc-roof village school outside Monrovia"
        )
    else:
        _location_detail = (
            "in Monrovia, Liberia — concrete block walls, zinc roof, wooden desks. "
            "Through the open louvred windows: busy Monrovia streets, yellow taxis, "
            "traders with goods on their heads, colourful painted storefronts, "
            "a joe bar with plastic chairs and a charcoal pot visible across the street"
        )
    _gemini_prompt = (
        f"A real documentary photograph of a school lesson on '{prompt}', "
        f"{_location_detail}. "
        "A teacher with dark skin and West African features stands at a concrete chalkboard. "
        "Liberian students in white-shirt dark-trouser school uniforms sit at worn wooden desks, "
        "engaged and attentive, writing in paper exercise books with biro. "
        "Warm tropical light. Chalk diagram visible on the board. "
        "Photorealistic, high resolution, National Geographic documentary photography. "
        "Shot on a DSLR with natural light. Real photograph."
    )

    # --- Gemini / Nano Banana image generation ---
    # Uses direct HTTP REST API — no SDK dependency, works on any server.
    # Models tried: Gemini 3 Flash Image first, then Imagen 3 variants.
    if agent in ("Nano Banana", "Auto") and GOOGLE_API_KEY:
        import json as _json
        import urllib.request as _ur
        import urllib.error as _ue
        _img_errs = []
        # Try both API versions — some models only exist under v1, others under v1beta
        _key = f"?key={GOOGLE_API_KEY}"

        def _http_post(url, payload):
            _req = _ur.Request(
                url,
                data=_json.dumps(payload).encode(),
                headers={"Content-Type": "application/json"},
                method="POST"
            )
            with _ur.urlopen(_req, timeout=60) as _r:
                return _json.loads(_r.read().decode())

        def _extract_img(resp_json):
            for cand in resp_json.get("candidates", []):
                for part in cand.get("content", {}).get("parts", []):
                    idata = part.get("inlineData") or part.get("inline_data")
                    if idata and idata.get("mimeType", "").startswith("image/"):
                        return idata["data"], idata["mimeType"]
            return None, None

        # ── Tier 1: generateContent IMAGE modality — try both API versions ───
        # Use the override model if the diagnostic already found a working one
        _working_model = st.session_state.get("_gemini_working_model", None)
        _flash_candidates = []
        if _working_model:
            _flash_candidates = [_working_model]
        else:
            # Confirmed image-capable models from ListModels diagnostic (March 2026)
            _flash_candidates = [
                ("v1beta", "gemini-2.5-flash-image"),               # Gemini 2.5 Flash Image ✅
                ("v1beta", "gemini-3.1-flash-image-preview"),       # Gemini 3.1 Flash Image ✅
                ("v1beta", "gemini-3-pro-image-preview"),           # Gemini 3 Pro Image ✅
                ("v1beta", "gemini-2.0-flash-exp-image-generation"),# Gemini 2.0 Flash Exp Image ✅
            ]
        # v1 uses snake_case, v1beta uses camelCase — send both so either version accepts it
        _payload_flash = {
            "contents": [{"parts": [{"text": _gemini_prompt}]}],
            "generationConfig": {
                "responseModalities": ["IMAGE", "TEXT"],
                "response_modalities": ["IMAGE", "TEXT"]
            }
        }
        _got_non_404 = False
        for _fc in _flash_candidates:
            if isinstance(_fc, tuple):
                _ver, _fm = _fc
            else:
                _ver, _fm = "v1beta", _fc.replace("models/", "")
            try:
                _url = f"https://generativelanguage.googleapis.com/{_ver}/models/{_fm}:generateContent{_key}"
                _resp_j = _http_post(_url, _payload_flash)
                _b64_data, _mime = _extract_img(_resp_j)
                if _b64_data:
                    st.session_state["_gemini_working_model"] = (_ver, _fm)
                    return f"data:{_mime};base64,{_b64_data}", "Nano Banana"
                _img_errs.append(f"{_ver}/{_fm}: responded, no image — {str(_resp_j)[:200]}")
                _got_non_404 = True
                break  # model reached, just no image output
            except _ue.HTTPError as _he:
                _body = ""
                try: _body = _he.read().decode()[:300]
                except: pass
                if _he.code == 429:
                    # Quota hit — wait and retry once
                    import time as _t; _t.sleep(4)
                    try:
                        _resp_j = _http_post(_url, _payload_flash)
                        _b64_data, _mime = _extract_img(_resp_j)
                        if _b64_data:
                            st.session_state["_gemini_working_model"] = (_ver, _fm)
                            return f"data:{_mime};base64,{_b64_data}", "Nano Banana"
                        _img_errs.append(f"{_ver}/{_fm}: 429 retry — no image in response")
                    except Exception as _re:
                        _img_errs.append(f"{_ver}/{_fm}: 429 retry failed — {_re}")
                    _got_non_404 = True
                    break
                _img_errs.append(f"{_ver}/{_fm}: HTTP {_he.code} — {_body[:200]}")
                if _he.code in (400, 401, 403):
                    _got_non_404 = True
                    break  # real error — stop
                # 404 = wrong name/version — keep trying

        # ── Tier 2: Imagen via predict — both API versions ────────────────────
        # Imagen 4 confirmed available on this key via ListModels
        _imagen_candidates = [
            ("v1beta", "imagen-4.0-fast-generate-001"),   # fastest
            ("v1beta", "imagen-4.0-generate-001"),         # standard
            ("v1beta", "imagen-4.0-ultra-generate-001"),   # highest quality
        ]
        _payload_imagen = {
            "instances": [{"prompt": _gemini_prompt}],
            "parameters": {"sampleCount": 1}
        }
        for _ver, _im in _imagen_candidates:
            try:
                _url = f"https://generativelanguage.googleapis.com/{_ver}/models/{_im}:predict{_key}"
                _resp_j = _http_post(_url, _payload_imagen)
                _preds = _resp_j.get("predictions", [])
                if _preds:
                    _img_b64 = (
                        _preds[0].get("bytesBase64Encoded") or
                        _preds[0].get("image", {}).get("bytesBase64Encoded")
                    )
                    if _img_b64:
                        return f"data:image/png;base64,{_img_b64}", "Nano Banana"
                _img_errs.append(f"{_ver}/{_im}: no image — {str(_resp_j)[:200]}")
                break
            except _ue.HTTPError as _he:
                _body = ""
                try: _body = _he.read().decode()[:300]
                except: pass
                _img_errs.append(f"{_ver}/{_im}: HTTP {_he.code} — {_body[:200]}")
                if _he.code in (400, 401, 403, 429):
                    break

        if _img_errs:
            st.session_state["_img_gen_errors"] = _img_errs

    return None, None

# === TEXT TO SPEECH ===

def speak_elevenlabs(text, voice_id="VU4qoZUtDRUWXB09nrAd", model_id="eleven_flash_v2_5"):
    """Generate speech using ElevenLabs streaming API. Returns base64 audio or None."""
    if not ELEVENLABS_API_KEY: return None, "No ElevenLabs API key"
    try:
        import re, urllib.request, urllib.error, json as jlib
        clean = str(text)
        clean = re.sub(r'<[^>]+>', '', clean)
        clean = re.sub(r'[#*_`~\[\](){}|>]', '', clean)
        clean = re.sub(r'-{3,}', ' ', clean)
        clean = re.sub(r'={3,}', ' ', clean)
        for old, new in [('\u2014', '-'), ('\u2013', '-'), ('\u2018', "'"), ('\u2019', "'"), ('\u201c', '"'), ('\u201d', '"'), ('\u2026', '...'), ('\u2022', ','), ('\u00a0', ' ')]:
            clean = clean.replace(old, new)
        clean = re.sub(r'\n{2,}', '. ', clean)
        clean = re.sub(r'\n', '. ', clean)
        clean = re.sub(r' {2,}', ' ', clean)
        clean = re.sub(r'\.{2,}', '.', clean)
        clean = re.sub(r'\.\s*\.', '.', clean)
        clean = clean.strip()
        if not clean or len(clean) < 10: return None, "Text too short after cleaning"
        if len(clean) > 1200: clean = clean[:1200] + ". See the full written version for complete details."
        # Use streaming endpoint for faster first-byte
        url = f"https://api.elevenlabs.io/v1/text-to-speech/{voice_id}/stream"
        payload = jlib.dumps({
            "text": clean,
            "model_id": model_id,
            "output_format": "mp3_22050_32",
        }).encode("utf-8")
        req = urllib.request.Request(url, data=payload, headers={
            "xi-api-key": ELEVENLABS_API_KEY,
            "Content-Type": "application/json",
            "Accept": "audio/mpeg",
        })
        # Stream response in chunks
        chunks = []
        try:
            with urllib.request.urlopen(req, timeout=120) as resp:
                while True:
                    chunk = resp.read(4096)
                    if not chunk: break
                    chunks.append(chunk)
        except urllib.error.HTTPError as he:
            _klen = len(ELEVENLABS_API_KEY)
            _kpre = ELEVENLABS_API_KEY[:4] + "..." if _klen > 4 else "(empty)"
            if he.code == 401:
                return None, f"Voice error: 401 Unauthorized. Key length={_klen}, starts with '{_kpre}'. Go to elevenlabs.io → Profile+API Key → regenerate a new key. Then update it in your Streamlit secrets.toml or environment."
            elif he.code == 429:
                return None, "Voice error: Rate limit or quota exceeded. Check your ElevenLabs plan usage."
            else:
                return None, f"Voice error: HTTP {he.code}"
        audio_bytes = b"".join(chunks)
        if len(audio_bytes) < 100: return None, "Empty audio response"
        # Validate it's actually MP3/audio, not a JSON error body
        _magic = audio_bytes[:3]
        if _magic not in (b'\xff\xfb', b'\xff\xf3', b'\xff\xf2', b'ID3') and not audio_bytes[:2] in (b'\xff\xfb', b'\xff\xf3', b'\xff\xf2'):
            # Try to surface the actual error message from the response body
            try:
                _err = jlib.loads(audio_bytes.decode("utf-8", errors="ignore"))
                _msg = _err.get("detail", {})
                if isinstance(_msg, dict): _msg = _msg.get("message", str(_err))
                return None, f"Voice error: {_msg}"
            except Exception:
                return None, "Voice error: unexpected non-audio response from ElevenLabs"
        b64 = base64.b64encode(audio_bytes).decode()
        return b64, "Teacher Pehpeh Voice"
    except Exception as e:
        return None, f"Voice error: {e}"

def highlight_result(text):
    import re
    t = text.strip()
    # Collapse excess blank lines
    t = re.sub(r'\n{3,}', '\n\n', t)
    # Bold
    t = re.sub(r'\*\*(.+?)\*\*', r'<strong style="color:#D4A843;background:rgba(212,168,67,.1);padding:1px 4px;border-radius:3px">\1</strong>', t)
    # Headings
    t = re.sub(r'^### (.+)$', r'<div style="color:#2B7DE9;font-weight:700;font-size:.95rem;margin:8px 0 2px;font-family:Playfair Display,serif">\1</div>', t, flags=re.MULTILINE)
    t = re.sub(r'^## (.+)$', r'<div style="color:#D4A843;font-weight:700;font-size:1rem;margin:10px 0 2px;font-family:Playfair Display,serif">\1</div>', t, flags=re.MULTILINE)
    t = re.sub(r'^# (.+)$', r'<div style="color:#D4A843;font-weight:700;font-size:1.05rem;margin:10px 0 2px;font-family:Playfair Display,serif">\1</div>', t, flags=re.MULTILINE)
    # Numbered list items
    t = re.sub(r'^(\d+)\.\s', r'<strong style="color:#2B7DE9">\1.</strong> ', t, flags=re.MULTILINE)
    # Keywords
    for kw in ["WASSCE","BECE","Key Point","Note:","Tip:","Important:","Answer Key","Teacher's Guide","Objective","Assessment"]:
        t = t.replace(kw, f'<span style="color:#D4A843;font-weight:600">{kw}</span>')
    # Split into paragraphs, wrap each in <p> with tight margin
    parts = re.split(r'\n\n+', t)
    out = []
    for part in parts:
        part = part.strip()
        if not part:
            continue
        # Already an HTML block element (div/h3/h4)? Don't wrap in <p>
        if part.startswith('<div') or part.startswith('<h'):
            lines = part.split('\n')
            out.append('\n'.join(lines))
        else:
            lines = part.split('\n')
            inner = '<br>'.join(line for line in lines)
            out.append(f'<p style="margin:2px 0 6px;line-height:1.55">{inner}</p>')
    return '\n'.join(out)

def clean_parent_output(text):
    import re
    raw_lines = text.split('\n')
    clean = []
    skip = False
    for line in raw_lines:
        lo = line.strip().lower()
        if any(lo.startswith(p) for p in [
            '# parent communication', '## key features', '### key features',
            '## why this works', '### why this works', '## analysis', '### analysis',
            '| element', '|---', '| **', '## message', '### message quality',
            '[spoken duration', 'key elements included:', '## format', '### format',
            '## tone', '# sms', '## sms', '# email format', '## delivery',
            '**key features', '**why this works', '**analysis']):
            skip = True
            continue
        if skip:
            if lo == '' or lo == '---':
                skip = False
                continue
            if any(lo.startswith(g) for g in ['dear ', 'good day', 'hello', 'hi ', 'greetings']):
                skip = False
            else:
                continue
        if any(x in lo for x in ['character count', 'characters /', 'this letter includes',
            'this message was', 'why this works', 'respects parent capacity',
            'achieves confirmation', 'no digital access', 'key features of',
            'this works for', 'warm, not accusatory', 'math focus',
            'practical home support', 'addresses low stem']):
            continue
        if lo.startswith('|') and '|' in lo[1:]:
            continue
        clean.append(line)
    result = '\n'.join(clean).strip()
    result = re.sub(r'\n{3,}', '\n\n', result)
    result = re.sub(r'^(\s*---\s*\n?)+', '', result).strip()
    return result

def strip_markdown_for_voice(text):
    """Strip markdown formatting so TTS speaks clean text, not symbols."""
    import re
    text = re.sub(r'\*{1,3}([^*]+)\*{1,3}', r'\1', text)
    text = re.sub(r'_{1,2}([^_]+)_{1,2}', r'\1', text)
    text = re.sub(r'#{1,6}\s*', '', text)
    text = re.sub(r'`+([^`]*)`+', r'\1', text)
    text = re.sub(r'\[([^\]]+)\]\([^)]+\)', r'\1', text)
    text = re.sub(r'^\s*[-*>]\s+', '', text, flags=re.MULTILINE)
    text = re.sub(r'\n{3,}', '\n\n', text)
    return text.strip()

def tts_player(text, key_suffix):
    """Simple 'Hear Results' button — one click, plays audio."""
    audio_key = f"tts_audio_{key_suffix}"
    if not ELEVENLABS_API_KEY:
        return
    if audio_key in st.session_state and st.session_state[audio_key]:
        aud = st.session_state[audio_key]
        _b64 = aud["b64"]
        # Use HTML audio — avoids Web Audio API conflict with st.audio_input mic widget
        st.markdown(
            f'<audio controls style="width:100%;height:36px;margin:4px 0">'
            f'<source src="data:audio/mp3;base64,{_b64}" type="audio/mp3">'
            f'</audio>',
            unsafe_allow_html=True
        )
        ac1, ac2 = st.columns([2,1])
        with ac1:
            st.download_button("📥 Download MP3", data=base64.b64decode(_b64), file_name=f"teacher_pehpeh_{key_suffix}.mp3", mime="audio/mp3", key=f"tts_dl_{key_suffix}")
        with ac2:
            if st.button("🗑️ Clear", key=f"tts_clr_{key_suffix}"):
                del st.session_state[audio_key]; st.rerun()
    else:
        if st.button(T("hear"), key=f"tts_gen_{key_suffix}", type="primary", use_container_width=True):
            with st.spinner(T("generating")):
                b64, src = speak_elevenlabs(text)
            if b64:
                st.session_state[audio_key] = {"b64": b64, "src": src}
                st.rerun()
            else:
                st.error(f"{T('audio_failed')}: {src}. {T('try_again')}")

# === SPEECH TO TEXT ===
def transcribe_audio(audio_bytes):
    """Transcribe audio using OpenAI Whisper. Returns text or None."""
    if not OAI or not OPENAI_API_KEY: return None
    try:
        import io
        c = openai.OpenAI(api_key=OPENAI_API_KEY)
        audio_file = io.BytesIO(audio_bytes)
        audio_file.name = "recording.wav"
        r = c.audio.transcriptions.create(model="whisper-1", file=audio_file)
        return r.text.strip() if r.text else None
    except Exception as e:
        return None

# === STUDENT ID CARD ===
def generate_student_card(student, school_name="", grade="", subject="", country="Liberia"):
    """Generate a student ID card as PNG bytes. Returns (png_bytes, filename) or (None, error)."""
    import io
    if not PIL_OK:
        return None, "Pillow not installed"
    try:
        W, H = 600, 340
        card = Image.new("RGB", (W, H), "#0F2247")
        draw = ImageDraw.Draw(card)
        # Try loading fonts, fall back to default
        try:
            font_title = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf", 20)
            font_name = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf", 24)
            font_body = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", 15)
            font_small = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", 12)
        except:
            font_title = ImageFont.load_default()
            font_name = font_title
            font_body = font_title
            font_small = font_title
        # Gold header bar
        draw.rectangle([0, 0, W, 56], fill="#D4A843")
        draw.text((20, 14), f"TEACHER PEHPEH - STUDENT ID", fill="#0F2247", font=font_title)
        # School name
        _school = school_name or "School"
        draw.text((20, 68), _school, fill="#F5D998", font=font_body)
        # Student name
        draw.text((20, 100), student["name"], fill="#FFFFFF", font=font_name)
        # Details
        y = 140
        details = [
            f"Grade: {grade}",
            f"Subject Focus: {subject}",
            f"Siblings: {student.get('sib', '—')}",
            f"Mother Education: {student.get('mom', '—')}",
            f"Computer Access: {student.get('cp', '—')}",
        ]
        for d in details:
            draw.text((20, y), d, fill="#C0C8D8", font=font_body)
            y += 22
        # Risk level
        rsk = []
        if student.get("mom") == "No HS": rsk.append("No HS Mom")
        if student.get("sm") == "Yes": rsk.append("Single Mom")
        if student.get("sib") == "8+": rsk.append("8+ siblings")
        if student.get("wk") == "Yes": rsk.append("Works")
        risk_color = "#EF5350" if len(rsk) >= 2 else "#FFA726" if rsk else "#66BB6A"
        risk_label = "Higher Risk" if len(rsk) >= 2 else "Some Risk" if rsk else "Lower Risk"
        draw.rectangle([20, y + 5, 170, y + 28], fill=risk_color, outline=risk_color)
        draw.text((28, y + 7), risk_label, fill="#FFFFFF", font=font_body)
        # QR Code
        if QR:
            qr_data = json.dumps({"name": student["name"], "school": _school, "grade": grade, "risk": risk_label}, ensure_ascii=False)
            qr = qrcode.QRCode(version=1, box_size=4, border=2)
            qr.add_data(qr_data)
            qr.make(fit=True)
            qr_img = qr.make_image(fill_color="#0F2247", back_color="#FFFFFF").convert("RGB")
            qr_img = qr_img.resize((120, 120))
            card.paste(qr_img, (W - 145, 80))
        else:
            draw.rectangle([W - 145, 80, W - 25, 200], fill="#1A2D50", outline="#D4A843")
            draw.text((W - 130, 130), "QR N/A", fill="#D4A843", font=font_body)
        # Footer
        draw.rectangle([0, H - 36, W, H], fill="#8B1A1A")
        draw.text((20, H - 30), f"Institute of Basic Technology (IBT) - {country}", fill="#F5D998", font=font_small)
        draw.text((W - 130, H - 30), "teacherpehpeh.org", fill="#F5D998", font=font_small)
        # Export as PNG bytes
        buf = io.BytesIO()
        card.save(buf, format="PNG")
        buf.seek(0)
        fname = f"student_card_{student['name'].replace(' ','_').lower()}.png"
        return buf.getvalue(), fname
    except Exception as e:
        return None, f"Card error: {e}"

