# === LOGO ===
_LOGO_B64=""
def get_b64():
    return _LOGO_B64

def show_logo(country=None):
    b=get_b64()
    flag=FLAGS.get(country,"") if country else ""
    # Flags hidden by default via opacity:0. Canvas test reveals them only if they
    # render as actual graphics (wide) — not as fallback text like "LR" on Windows.
    detect_js=('<script>(function(){'+
        'var spans=document.querySelectorAll(".tp-flag");'+
        'spans.forEach(function(s){'+
            'var cv=document.createElement("canvas"),ctx=cv.getContext("2d");'+
            'ctx.font="32px serif";'+
            'var fw=ctx.measureText(s.dataset.flag).width;'+
            'var lw=ctx.measureText("LR").width;'+
            'if(fw>lw*1.5){s.style.opacity="1";}'+  # real flag renders much wider than two Latin letters
        '});'+
    '})();</script>') if flag else ""
    flag_span=(f'<span class="tp-flag" style="font-size:3rem;opacity:0;transition:opacity .3s" '+
               f'data-flag="{flag}">{flag}</span>') if flag else ""
    if b: st.markdown(
        f'<div style="text-align:center;padding:0 0 .2rem;margin-top:-1.5rem;display:flex;align-items:center;justify-content:center;gap:16px">'+
        f'{flag_span}<img src="data:image/png;base64,{b}" style="max-height:clamp(100px,20vw,280px);width:auto;filter:drop-shadow(0 4px 12px rgba(212,168,67,.3))">{flag_span}</div>'+
        detect_js,unsafe_allow_html=True)
    else: st.markdown(f'<div style="text-align:center"><h1 style="color:{C_GOLD}">Teacher Pehpeh by IBT</h1></div>',unsafe_allow_html=True)

def ico(s=20):
    b=get_b64()
    return f'<img src="data:image/png;base64,{b}" style="height:{s}px;width:{s}px;vertical-align:middle;border-radius:50%">' if b else ""

def pprog(stg,tot,msg):
    b=get_b64(); lit=min(stg,tot); pct=int(lit/tot*100)
    # Animated pepper icons filling up with pulsing "Generating" text
    pepfill="".join(f'<img src="data:image/png;base64,{b}" style="height:40px;width:40px;margin:0 4px;opacity:{"1" if i<lit else ".15"};{"animation:peppop .4s ease;" if i==lit-1 else ""}{"filter:grayscale(100%);" if i>=lit else ""}border-radius:50%;transition:all .3s">' for i in range(tot)) if b else ""
    pepfill_fallback="".join(f'<img src="data:image/png;base64,{b}" style="height:36px;width:36px;margin:0 4px;opacity:{"1" if i<lit else ".15"};{"animation:peppop .4s ease;" if i==lit-1 else ""}border-radius:50%;transition:all .3s">' for i in range(tot)) if b else ""
    icons=pepfill if b else pepfill_fallback
    # Status messages with model icons
    status_icon={"⏳ Teacher Pehpeh is cooking...":ico(22),"Asking ChatGPT...":"🟢","Asking Claude...":"🟣","Asking Gemini...":"🔵","Combining the best...":"🔀","🎨 Creating illustration...":"🎨","✅ Done! Content is ready!":"✅"}.get(msg,ico(22))
    done_class="animation:none;color:#10B981" if "Done" in msg else "animation:genpulse 1.2s ease-in-out infinite"
    return f'''<style>
@keyframes genpulse {{ 0%,100%{{opacity:.7;transform:scale(1)}} 50%{{opacity:1;transform:scale(1.03)}} }}
@keyframes peppop {{ 0%{{transform:scale(0.3);opacity:0}} 50%{{transform:scale(1.2)}} 100%{{transform:scale(1);opacity:1}} }}
@keyframes barshine {{ 0%{{background-position:-200% 0}} 100%{{background-position:200% 0}} }}
</style>
<div style="background:{C_NAVY_L};border:2px solid {C_GOLD};border-radius:16px;padding:20px 24px;margin:12px 0;text-align:center">
<div style="display:flex;justify-content:center;align-items:center;margin-bottom:14px;flex-wrap:wrap">{icons}</div>
<div style="background:#1a2744;border-radius:10px;height:14px;overflow:hidden;margin-bottom:12px;border:1px solid #2d3748">
<div style="background:linear-gradient(90deg,{C_RED},{C_GOLD},{C_RED});background-size:200% 100%;animation:barshine 2s linear infinite;height:100%;width:{pct}%;border-radius:10px;transition:width .5s ease"></div></div>
<div style="{done_class};font-size:1.1rem;font-weight:700;color:{C_GOLD};letter-spacing:.5px">{status_icon} {msg}</div>
</div>'''

# === PROMPTS ===
def _p():
    return (
        "You are Teacher Pehpeh — a warm, cheerful, wise AI teaching assistant created by IBT (Institute of Basic Technology) for Liberian schools. "
        "You respond to the name Teacher Pehpeh. When called by name, say: 'Hello, how can Teacher Pehpeh help you today!'\n\n"

        # === CORE PERSONA ===
        "PERSONA & TONE: Speak like a trusted teacher or village elder — warm, conversational, full of wisdom and practical advice. "
        "Always be supportive, understanding, encouraging, and kind. "
        "Use culturally relevant African idioms, proverbs, and everyday West African/Liberian examples: fetching water, clearing the farm, fixing a radio, preparing cassava, market trade, local transportation, Koloqua (Liberian English). "
        "When you explain in Liberian terms, skip all other context — go straight to the Liberian example only. "
        "Check and use words from the Koloqua lexicon (https://libco406423561.wordpress.com/koloqua-dictionary/) wherever natural. "
        "Avoid overly technical jargon unless specifically asked. Use storytelling and analogies familiar to African learners. "
        "Emphasize clarity, empathy, and community values. Add encouragement that reflects African communal culture.\n\n"

        # === STUDENT GROUPS & SOCIOECONOMIC CONTEXT ===
        "STUDENT GROUPS (always use Group labels, never student names):\n"
        "- Group 1: 0–4 siblings. Most study time available. Parents likely have some education. May have some access to resources.\n"
        "- Group 2: 5–8 siblings. Limited study time. Mixed parental education. Constrained resources.\n"
        "- Group 3: More than 8 siblings. Very little study time. Parents likely have minimal formal education. Very limited resources.\n"
        "Always consider: socioeconomic background, access to computers (58% of students have none — paper-first always), parents' education level, and number of siblings. "
        "Infer who has the most time and curate assignments accordingly. "
        "Do NOT state student aspirations. Do NOT use student real names. "
        "Always provide a study tip and time estimate for struggling students (Groups 2 and 3).\n\n"

        # === ASSIGNMENT RULES ===
        "ASSIGNMENT RULES:\n"
        "- Max 3 problems per group. Be succinct.\n"
        "- Each group works on the same topic/subject but at a difficulty level matched to their time and background.\n"
        "- Draw a horizontal line between each group's assignment.\n"
        "- Provide a short explanation or prompt to help struggling students (Groups 2 & 3) who have no time.\n"
        "- All tips must be self-contained — students have NO internet access, so all help must be inside the assignment itself.\n"
        "- Use terms and examples relevant to Liberian students (markets, farms, Monrovia, county life, WAEC/WASSCE context).\n"
        "- Always behave like a high school and elementary school teacher — age-appropriate, patient, clear.\n\n"

        # === SOCRATIC MODE ===
        "SOCRATIC METHOD (when a student identifies as a student and asks for homework help):\n"
        "- Ask how many siblings they have first, then assign them to their Group.\n"
        "- Employ the Socratic method at their level: gently nudge them toward the answer with questions.\n"
        "- Each time they are stuck, ask a leading question. Pause and check where they are.\n"
        "- Keep giving clues and asking questions, but NEVER give away the answer directly.\n"
        "- When explaining in Liberian terms, skip all other context — use only the Liberian/African analogy.\n\n"

        # === WASSCE / EXAM MODE ===
        "WASSCE PRACTICE EXAM RULES:\n"
        "- Present questions in groups of 5 per subject.\n"
        "- Let students select answers, then grade and give feedback.\n"
        "- Regulate difficulty based on previous performance (do better → harder; struggle → easier).\n"
        "- Always praise the student before adjusting difficulty.\n"
        "- Provide process-of-elimination hints before each set.\n"
        "- Remind students about answer sheet shading: fill the ENTIRE bubble with HB pencil — no ticks, no dots, no crosses.\n"
        "- Start WASSCE sessions with: 'I say how you doing? Teacher Pehpeh is here to help you prepare for the WASSCE...'\n"
        "- Do NOT reveal answers until the student has responded.\n"
        "- After one subject set (5 questions), move to the next subject.\n\n"

        # === IMPROVEMENT SUGGESTIONS ===
        "IMPROVEMENT SUGGESTIONS: When asked how to help students improve their chances of passing, always base suggestions on "
        "parents' background, education level, number of siblings, and limited study time. Keep suggestions practical and achievable.\n\n"

        # === LIBERIAN CONTEXT (ALWAYS ON) ===
        "LIBERIAN REALITY (permanent grounding — apply to ALL responses):\n"
        "- Students are in Liberia. Schools may lack electricity, running water, textbooks, or internet.\n"
        "- WAEC/WASSCE is the high-stakes exit exam. Bubble-sheet shading errors are a top failure cause.\n"
        "- Many students walk long distances to school. Many work at home or on farms after school.\n"
        "- Parents may be traders, farmers, or market women with little formal schooling.\n"
        "- Community, family, and respect for elders are central values — honor this in tone.\n"
        "- IBT (Institute of Basic Technology) built this tool to serve these students. Always represent IBT with pride.\n"
        "- When explaining any concept, default to Liberian/West African context first. No need to explain Western context first.\n"
        "- All examples should feel like they come from someone who knows Liberia from the inside."
    )
def _g():
    return "Groups: 1(0-4 siblings,most time), 2(5-8,limited), 3(8+,very little). Consider socioeconomic, computer access, parents' ed."
def _r():
    return "Rules: stated resources only, max 3 problems/group, self-contained tips, WAEC format for exams, African context, Socratic method, print-ready. Use **bold** for key terms, objectives, important concepts, and answer highlights."

def build_sys(reg,cty,grd,subj,task,cls,res,lng,abl,tm,top,sch="",mano_ctx=""):
    s_tag=f",School:{sch}" if sch else ""
    mano_block=f"\n\n{mano_ctx}" if mano_ctx else ""
    return f"{_p()}\nCLASS: {cty},{reg},{grd},{subj},{task},{cls},{res},{lng},{abl},Time:{tm},Topic:{top}{s_tag}\n{_g()}\n{_kb()}\nPhysics=extra scaffolding. Group 3=SHORT. 58% no computer=paper first.{mano_block}\n{_r()}"

def build_chat(reg,cty,grd,subj,cls,res,lng,abl,sch="",curr_ctx="",mano_ctx=""):
    s_tag=f",School:{sch}" if sch else ""
    curr_block=f"\nMOE CURRICULUM CONTEXT:\n{curr_ctx}\nUse this when answering questions about curriculum, topics, or lesson planning." if curr_ctx else ""
    mano_block=f"\n\n{mano_ctx}" if mano_ctx else ""
    return f"{_p()}\nWhen greeted: 'Hello, how can Teacher Pehpeh help you today!'\nCLASS: {cty},{reg},{grd},{subj},{cls},{res},{lng},{abl}{s_tag}\n{_g()}\n{_kb()}\nIntervention WORKS. Teacher's work matters.{curr_block}{mano_block}\n{_r()}"

def build_free_chat():
    """Free-flowing chat system prompt — independent of classroom config."""
    return (
        f"{_p()}\n"
        "You are Teacher Pehpeh, an educational assistant for African students and teachers built by IBT (Institute of Basic Technology). "
        "You answer questions on any subject — Mathematics, Sciences, Languages, Literature, History, and more. "
        "You also help users with any aspect of the Teacher Pehpeh app itself: how to use features, troubleshoot problems, navigate sections, or understand what the app can do. "
        "When generating MCQs, always format them as:\n"
        "1. Question text\nA) option\nB) option\nC) option\nD) option\n\nAnswer: X\n\n"
        "TONE & LENGTH RULES — non-negotiable:\n"
        "- Greetings (hi, hello, good morning, etc.): reply in ONE sentence only. Example: 'Hi! I'm here to help — what do you need?' No proverbs, no cultural phrases, no elaboration.\n"
        "- Simple questions: 1-3 sentences max.\n"
        "- Explanations: under 80 words unless the user asks for a full lesson.\n"
        "- Never use African proverbs or sayings. Never start with a long preamble.\n"
        "- Never repeat the question back. Get straight to the answer.\n"
        f"{_kb()}\n{_r()}"
    )

def build_stu(reg,cty,grd,subj,cls,res,lng,abl,info,sch=""):
    s_tag=f",School:{sch}" if sch else ""
    return f"{_p()}\nCLASS: {cty},{reg},{grd},{subj},{cls},{res},{lng},{abl}{s_tag}\nSTUDENT: {info}\n{_kb()}\nTargeted advice. Compare to data. Risk factors. Interventions.\n{_r()}"

# === AI ===
def _sub_blocked():
    """Return upgrade message if subscription is not active, else None."""
    if not SUBSCRIPTION_ACTIVE:
        tier_msg = "expired" if _SUB_TIER == "expired" else "not yet active"
        return (f"🔒 **AI generation is paused** — your school subscription is {tier_msg}.\n\n"
                f"Your student data and past content are safe. "
                f"Contact IBT to renew: [institutebasictechnology.org](https://www.institutebasictechnology.org)")
    return None

def ask_gpt(sp,q,h=None):
    blocked = _sub_blocked()
    if blocked: return blocked
    if not OAI or not OPENAI_API_KEY: return None
    try:
        m=[{"role":"system","content":sp}]+(h or [])+[{"role":"user","content":q}]
        return openai.OpenAI(api_key=OPENAI_API_KEY).chat.completions.create(model="gpt-4o-mini",messages=m,max_tokens=3000,temperature=.7).choices[0].message.content
    except Exception as e: return f"⚠️ {e}"

def ask_cl(sp,q,h=None,max_t=3000):
    blocked = _sub_blocked()
    if blocked: return blocked
    if not ANT or not ANTHROPIC_API_KEY: return None
    try:
        m=list(h or [])+[{"role":"user","content":q}]
        return anthropic.Anthropic(api_key=ANTHROPIC_API_KEY).messages.create(model="claude-haiku-4-5-20251001",max_tokens=max_t,system=sp,messages=m).content[0].text
    except Exception as e: return f"⚠️ {e}"

def ask_gem(sp,q):
    blocked = _sub_blocked()
    if blocked: return blocked
    if not GEM or not GOOGLE_API_KEY: return None
    try:
        genai.configure(api_key=GOOGLE_API_KEY)
        return genai.GenerativeModel("gemini-2.5-flash",system_instruction=sp).generate_content(q).text
    except Exception as e: return f"⚠️ Gemini: {e}"

def best(sp,q,h=None):
    """Try text models"""
    for fn,nm in [(ask_cl,"Claude"),(ask_gpt,"ChatGPT")]:
        r=fn(sp,q,h)
        if r and not str(r).startswith("⚠️"): return r,nm
    r=ask_gem(sp,q)
    if r and not str(r).startswith("⚠️"): return r,"Gemini"
    return "⚠️ No models responded.",None

