    if _login_required() and not _is_logged_in():
        _restore_session_from_token()

    if _login_required() and not _is_logged_in():
        _show_login_screen()
        st.stop()

    # ── PRIVACY CONSENT + CONNECTIVITY SNAPSHOT ────────────────────
    # Non-admin accounts see a consent dialog once per week.
