                f'<span style="font-size:10px;padding:1px 7px;border-radius:10px;background:rgba(99,102,241,.2);color:#a5b4fc;font-weight:600;border:1px solid rgba(99,102,241,.3)">⚡ {_n} AI engine{"s" if _n != 1 else ""} available</span>'
                f'</div>',
