                            _iv_sm  = _iv_p.get("sm","Unknown")
                            _iv_sib = _iv_p.get("sib","0-4")
                            _iv_wk  = _iv_p.get("wk","Unknown")
                            _iv_cp  = _iv_p.get("cp","Unknown")

                            _iv_rf_list = []
